/**
 * LLM-powered summarizer for pi-speak notification ping.
 *
 * Uses OpenRouter API with a cheap fast model to generate
 * a 2-sentence "what was done, where" summary for the voice ping.
 */

import type { SpeakConfig } from "./config/index";
import { debug, debugError } from "./debug";

const OPENROUTER_URL = "https://openrouter.ai/api/v1/chat/completions";
const DEFAULT_MAX_TOKENS = 60;
const DEFAULT_TIMEOUT_MS = 5000;

export interface SummarizeContext {
  /** What the assistant did (truncated text of the response) */
  responseText: string;
  /** tmux session name (if available) */
  sessionName?: string;
  /** Config for the summarizer */
  config: SpeakConfig["summarizer"];
  /** API key override */
  apiKey?: string;
  /** Fallback ping text */
  fallbackPingText: string;
}

/** Generate a 2-sentence voice ping summary via OpenRouter */
export async function summarizeForPing(ctx: SummarizeContext): Promise<string> {
  // Check if summarizer is enabled
  if (!ctx.config.enabled) {
    debug("summarizer: disabled — using fallback summary");
    return fallbackSummary(ctx);
  }

  // Use API key from context (config) or environment
  const apiKey = ctx.apiKey ?? process.env.OPENROUTER_API_KEY;
  if (!apiKey) {
    debug("summarizer: no OPENROUTER_API_KEY — using fallback summary");
    return fallbackSummary(ctx);
  }

  const model = ctx.config.model;
  const maxTokens = ctx.config.maxTokens ?? DEFAULT_MAX_TOKENS;
  const timeoutMs = ctx.config.timeoutMs ?? DEFAULT_TIMEOUT_MS;
  const where = ctx.sessionName ? ` in the "${ctx.sessionName}" session` : "";

  try {
    const response = await fetch(OPENROUTER_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${apiKey}`
      },
      body: JSON.stringify({
        model,
        max_tokens: maxTokens,
        messages: [
          {
            role: "system",
            content:
              "You write ultra-concise voice notifications. Always include the session name if given. Max 2 sentences. Be specific about what was done."
          },
          {
            role: "user",
            content: `Write a voice notification: what was done${where}. What: ${ctx.responseText.slice(0, 500)}`
          }
        ]
      }),
      signal: AbortSignal.timeout(timeoutMs)
    });

    if (!response.ok) {
      debug(`summarizer: OpenRouter error ${response.status}`);
      return fallbackSummary(ctx);
    }

    const data = (await response.json()) as { choices?: Array<{ message?: { content?: string } }> };
    const summary = data.choices?.[0]?.message?.content?.trim();
    if (!summary) {
      debug("summarizer: empty response from OpenRouter");
      return fallbackSummary(ctx);
    }

    debug(`summarizer: LLM summary = "${summary}"`);
    return summary;
  } catch (err) {
    debugError("summarizer: fetch failed", err);
    return fallbackSummary(ctx);
  }
}

/** Fallback: simple truncate-based summary if LLM is unavailable */
function fallbackSummary(ctx: SummarizeContext): string {
  const where = ctx.sessionName ? ` in ${ctx.sessionName}` : "";
  const preview = ctx.responseText.slice(0, 100).replace(/\n/g, " ").trim();
  return `${ctx.fallbackPingText}${where}. ${preview}…`;
}

/**
 * Default configuration values for pi-speak.
 */

import type { SpeakConfig } from "./schema";

export const DEFAULT_CONFIG: SpeakConfig = {
  $schema: "https://raw.githubusercontent.com/nikbrunner/pi-speak/main/src/config/schema.json",
  version: 1,
  tts: {
    voiceId: "Sierra",
    bitrate: "192k",
    speed: 0,
    pitch: 1.0,
    maxChunkChars: 900
  },
  behavior: {
    shortcut: "alt+r",
    pingEnabled: true,
    pingOnStartEnabled: false,
    fallbackPingText: "Work finished."
  },
  summarizer: {
    enabled: true,
    model: "google/gemini-2.5-flash-lite",
    maxTokens: 100,
    timeoutMs: 5000
  },
  debug: {
    enabled: true,
    logPath: "~/.pi-speak-debug.log",
    logMaxBytes: 2 * 1024 * 1024
  },
  api: {
    unrealSpeechKey: null,
    openRouterKey: null
  }
};

export function generateDefaultConfigJson(): string {
  return JSON.stringify(DEFAULT_CONFIG, null, 2);
}

/**
 * Configuration migrations for pi-speak.
 *
 * Handles upgrades from older config versions to the current schema.
 */

import { SCHEMA_URL } from "./constants";
import { DEFAULT_CONFIG } from "./defaults";
import type { SpeakConfig } from "./schema";

// ─── Types ───────────────────────────────────────────────────────────────────

interface LegacyConfigV0 {
  voiceId?: string;
  bitrate?: string;
  speed?: number;
  pitch?: number;
  maxChunkChars?: number;
  shortcut?: string;
  debug?: boolean;
  summarizerModel?: string;
}

// ─── Migrations ──────────────────────────────────────────────────────────────

/**
 * Migrate v0 (flat) config to v1 (nested) schema.
 */
function migrateV0ToV1(raw: LegacyConfigV0): SpeakConfig {
  return {
    $schema: SCHEMA_URL,
    version: 1,
    tts: {
      voiceId: raw.voiceId ?? DEFAULT_CONFIG.tts.voiceId,
      bitrate: raw.bitrate ?? DEFAULT_CONFIG.tts.bitrate,
      speed: raw.speed ?? DEFAULT_CONFIG.tts.speed,
      pitch: raw.pitch ?? DEFAULT_CONFIG.tts.pitch,
      maxChunkChars: raw.maxChunkChars ?? DEFAULT_CONFIG.tts.maxChunkChars
    },
    behavior: {
      shortcut: raw.shortcut ?? DEFAULT_CONFIG.behavior.shortcut,
      pingEnabled: DEFAULT_CONFIG.behavior.pingEnabled,
      pingOnStartEnabled: DEFAULT_CONFIG.behavior.pingOnStartEnabled,
      fallbackPingText: DEFAULT_CONFIG.behavior.fallbackPingText
    },
    summarizer: {
      enabled: DEFAULT_CONFIG.summarizer.enabled,
      model: raw.summarizerModel ?? DEFAULT_CONFIG.summarizer.model,
      maxTokens: DEFAULT_CONFIG.summarizer.maxTokens,
      timeoutMs: DEFAULT_CONFIG.summarizer.timeoutMs
    },
    debug: {
      enabled: raw.debug ?? DEFAULT_CONFIG.debug.enabled,
      logPath: DEFAULT_CONFIG.debug.logPath,
      logMaxBytes: DEFAULT_CONFIG.debug.logMaxBytes
    },
    api: {
      unrealSpeechKey: DEFAULT_CONFIG.api.unrealSpeechKey,
      openRouterKey: DEFAULT_CONFIG.api.openRouterKey
    }
  };
}

// ─── Export migration function ───────────────────────────────────────────────

export const CURRENT_VERSION = 1;

/**
 * Migrate raw config to current schema version.
 */
export function migrate(raw: unknown, fromVersion: number): SpeakConfig {
  const cfg = raw as Record<string, unknown>;

  if (fromVersion < 1) {
    return migrateV0ToV1(cfg as LegacyConfigV0);
  }

  // Future migrations:
  // if (fromVersion < 2) { ... }

  return cfg as SpeakConfig;
}

/**
 * Zod schemas for pi-speak configuration.
 *
 * Uses Zod for runtime validation and TypeScript inference.
 */

import { z } from "zod";
import { SCHEMA_URL } from "./constants";

// ─── Sub-schemas ─────────────────────────────────────────────────────────────

export const TTSConfigSchema = z.object({
  // https://docs.v8.unrealspeech.com/
  voiceId: z.string().default("Sierra"),
  bitrate: z.string().default("192k"),
  speed: z.number().min(-1).max(1).default(0),
  pitch: z.number().min(0.5).max(1.5).default(1.0),
  maxChunkChars: z.number().int().min(1).max(1000).default(900)
});

export const BehaviorConfigSchema = z.object({
  shortcut: z.string().default("alt+r"),
  pingEnabled: z.boolean().default(true),
  pingOnStartEnabled: z.boolean().default(false),
  fallbackPingText: z.string().default("Work finished.")
});

export const SummarizerConfigSchema = z.object({
  // https://openrouter.ai/models
  enabled: z.boolean().default(true),
  model: z.string().default("openai/gpt-oss-20b"),
  maxTokens: z.number().int().min(1).max(500).default(60),
  timeoutMs: z.number().int().min(1000).max(60000).default(5000)
});

export const DebugConfigSchema = z.object({
  enabled: z.boolean().default(true),
  logPath: z.string().default("~/.pi-speak-debug.log"),
  logMaxBytes: z
    .number()
    .int()
    .min(1024)
    .max(10 * 1024 * 1024)
    .default(2 * 1024 * 1024)
});

export const ApiConfigSchema = z.object({
  unrealSpeechKey: z.string().nullable().default(null),
  openRouterKey: z.string().nullable().default(null)
});

// ─── Main schema ─────────────────────────────────────────────────────────────

export { SCHEMA_URL } from "./constants";

export const SpeakConfigSchema = z.object({
  $schema: z.string().url().default(SCHEMA_URL),
  version: z.number().int().min(0).default(1),
  tts: TTSConfigSchema,
  behavior: BehaviorConfigSchema,
  summarizer: SummarizerConfigSchema,
  debug: DebugConfigSchema,
  api: ApiConfigSchema
});

export type SpeakConfig = z.infer<typeof SpeakConfigSchema>;

/**
 * Configuration module for pi-speak extension.
 *
 * Reads from ~/.config/pi-speak/config.json, with sensible defaults.
 * Uses Zod for runtime validation and supports versioned migrations.
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { debug } from "../debug";
import { CONFIG_PATH } from "./constants";
import { DEFAULT_CONFIG, generateDefaultConfigJson } from "./defaults";
import { CURRENT_VERSION, migrate } from "./migrations";
import { SpeakConfigSchema, type SpeakConfig } from "./schema";

// ─── Load ───────────────────────────────────────────────────────────────────

/** Warn about unknown config keys that will be ignored */
function warnUnknownKeys(raw: Record<string, unknown>): void {
  const knownKeys = new Set(["$schema", "version", "tts", "behavior", "summarizer", "debug", "api"]);
  const unknownKeys = Object.keys(raw).filter(key => !knownKeys.has(key));

  if (unknownKeys.length > 0) {
    debug(`loadConfig: WARNING — ignoring unknown config keys: ${unknownKeys.join(", ")}`);
  }
}

/** Validation errors to report to user */
let pendingValidationErrors: { path: string; message: string; value: unknown }[] = [];

/**
 * Extracts the faulty value from a Zod issue for display.
 */
function extractFaultyValue(issue: { code: string; path: PropertyKey[] }, raw: Record<string, unknown>): unknown {
  if (issue.code === "invalid_type") return (issue as { received?: unknown }).received;
  // For range errors (too_big, too_small), return the actual config value at the path
  const path = issue.path.join(".");
  return path in raw ? raw[path] : undefined;
}

/**
 * Captures validation errors from a Zod result into the module state.
 */
function captureValidationErrors(
  result: { error: { issues: Array<{ code: string; path: PropertyKey[]; message: string }> } },
  raw: Record<string, unknown>
): void {
  pendingValidationErrors = result.error.issues.map(issue => ({
    path: issue.path.join(".") || "root",
    message: issue.message,
    value: extractFaultyValue(issue as { code: string; path: string[] }, raw)
  }));
}

/**
 * Returns validation errors (can be called multiple times without consuming).
 */
export function getValidationErrors(): { path: string; message: string; value: unknown }[] {
  return pendingValidationErrors;
}

export function loadConfig(): SpeakConfig {
  let rawConfig: Record<string, unknown> = {};
  let parseError = false;

  if (existsSync(CONFIG_PATH)) {
    try {
      rawConfig = JSON.parse(readFileSync(CONFIG_PATH, "utf-8"));
      debug(`loadConfig: loaded from ${CONFIG_PATH}`);
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      debug(`loadConfig: failed to parse ${CONFIG_PATH}: ${message}`);
      debug(`loadConfig: using defaults due to parse error`);
      parseError = true;
    }
  } else {
    debug(`loadConfig: no config file at ${CONFIG_PATH}, using defaults`);
    return { ...DEFAULT_CONFIG };
  }

  if (parseError) {
    pendingValidationErrors = [{ path: "config", message: "JSON parse error", value: undefined }];
    return { ...DEFAULT_CONFIG };
  }

  warnUnknownKeys(rawConfig);

  const fileVersion = (rawConfig.version as number | undefined) ?? 0;

  // Migrate if needed and save back to file
  if (fileVersion < CURRENT_VERSION) {
    debug(`loadConfig: migrating from v${fileVersion} to v${CURRENT_VERSION}`);
    const migratedConfig = migrate(rawConfig, fileVersion);
    saveConfig(migratedConfig);
    return migratedConfig;
  }

  const result = SpeakConfigSchema.safeParse(rawConfig);

  if (!result.success) {
    captureValidationErrors(result, rawConfig);
    const errors = result.error.issues.map(issue => `${issue.path.join(".")}: ${issue.message}`).join("; ");
    debug(`loadConfig: validation failed — ${errors}`);
    debug(`loadConfig: using defaults due to validation errors`);
    return { ...DEFAULT_CONFIG };
  }

  debug(
    `loadConfig: voiceId=${result.data.tts.voiceId} bitrate=${result.data.tts.bitrate} ` +
      `speed=${result.data.tts.speed} pitch=${result.data.tts.pitch} shortcut=${result.data.behavior.shortcut}`
  );

  return result.data;
}

/** Save config to file */
function saveConfig(config: SpeakConfig): void {
  try {
    writeFileSync(CONFIG_PATH, JSON.stringify(config, null, 2) + "\n");
    debug(`saveConfig: saved migrated config to ${CONFIG_PATH}`);
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    debug(`saveConfig: failed to save ${CONFIG_PATH}: ${message}`);
  }
}

// ─── Revalidate ───────────────────────────────────────────────────────────────

/**
 * Re-reads and re-validates the config file, updating validation errors.
 * Call this on user input to detect config fixes without reloading.
 */
export function revalidateConfig(): void {
  if (!existsSync(CONFIG_PATH)) {
    pendingValidationErrors = [];
    return;
  }

  const rawConfig = (() => {
    try {
      return JSON.parse(readFileSync(CONFIG_PATH, "utf-8"));
    } catch {
      pendingValidationErrors = [{ path: "config", message: "JSON parse error", value: undefined }];
      return null;
    }
  })();

  if (rawConfig === null) return;

  const result = SpeakConfigSchema.safeParse(rawConfig);
  pendingValidationErrors = result.success ? [] : (captureValidationErrors(result, rawConfig), pendingValidationErrors);
}

// ─── Init ────────────────────────────────────────────────────────────────────

export function initConfig(): void {
  if (existsSync(CONFIG_PATH)) return;

  try {
    mkdirSync(CONFIG_PATH.replace("/config.json", ""), { recursive: true });
    writeFileSync(CONFIG_PATH, generateDefaultConfigJson() + "\n");
    debug(`initConfig: created default config at ${CONFIG_PATH}`);
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    debug(`initConfig: failed to create ${CONFIG_PATH}: ${message}`);
  }
}

// Re-export types and schema for external use
export type { SpeakConfig } from "./schema";
export { SpeakConfigSchema, SCHEMA_URL } from "./schema";

